def swap_odd_even_bits(x):
    if x < 0:
        raise ValueError("Input must be a non-negative integer for bit swapping.")

    if x == 0:
        return 0

    max_bits = x.bit_length()

    even_mask = 0
    odd_mask = 0
    for i in range(max_bits):
        if i % 2 == 0:
            even_mask |= (1 << i)
        else:
            odd_mask |= (1 << i)

    even_bits_shifted = (x & even_mask) << 1
    odd_bits_shifted = (x & odd_mask) >> 1

    return even_bits_shifted | odd_bits_shifted
